+interface FederationEnvelope {
+  id: string;
+  nonce: string;
+  timestamp: string;
+  sourceNodeId: string;
+  targetNodeId: string;
+  sessionId: string;
+  payload: unknown;
+  signature: string;
+  protocolVersion: string;
