+
+interface ServiceContainer {
+  register: <T>(name: string, service: T) => void;
+  get: <T>(name: string) => T | undefined;
+  has: (name: string) => boolean;
+  getServiceNames: () => string[];
+}
+
+interface PluginContext {
+  config: Record<string, unknown>;
