+    return {
+      defaultAction: 'redact',
+      overrides: {},
+      hashAlgorithm: 'sha256',
+      hashSalt: '',
+      redactionPlaceholder: '[REDACTED:{type}]',
+    };
+  }
+
+  static defaultPolicyMatrix(): Record<PIIType, Record<TrustLevel, PIIAction>> {
+    return { ...DEFAULT_POLICY_MATRIX };
+  }
+}

